mapper.sql:
SELECT A.SEQ ,A.VOC_AGNT_CD ,(SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = A.VOC_AGNT_CD AND ROWNUM = 1) AS ORGN_NAME ,A.VOC_AGNT_ID ,A.VOC_AGNT_ID AS USR_ID ,B.USR_NM AS VOC_AGNT_NAME ,B.MBLPHN_NUM AS MOBILE_NUM ,A.USE_YN ,TO_CHAR(A.REGST_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS REGST_DTTM ,FN_GET_USRNM(A.REGST_ID) AS REGST_NAME ,TO_CHAR(A.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM ,FN_GET_USRNM(A.RVISN_ID) AS RVISN_NAME FROM NMCP_ACEN_VOC_AGNT@DL_MCP A ,CMN_USR_MST B WHERE A.VOC_AGNT_ID = B.USR_ID AND B.USG_YN IN ('Y', 'S')
AND A.VOC_AGNT_CD = #{cntpntShopId}
AND UPPER(B.USR_NM) LIKE UPPER(#{searchName}) || '%'
AND A.VOC_AGNT_ID = #{searchName}
AND B.MBLPHN_NUM = #{searchName}
ORDER BY A.SEQ DESC

mapper.select:
/*AcenVocAgntMapper.getOrgnIdCnt*/
SELECT COUNT(*)
FROM ORG_ORGN_INFO_MST
WHERE ORGN_ID = #{orgnId}

/*AcenVocAgntMapper.getUserIdCnt*/
SELECT COUNT(*)
FROM CMN_USR_MST
WHERE USR_ID = #{usrId}
AND USG_YN IN ('Y', 'S')

/*AcenVocAgntMapper.getAcenVocAgntDupCnt*/
SELECT COUNT(*)
FROM NMCP_ACEN_VOC_AGNT@DL_MCP
WHERE VOC_AGNT_CD = #{vocAgntCd}
	AND VOC_AGNT_ID = #{usrId}

mapper.insert:
/*AcenVocAgntMapper.insertAcenVocAgnt*/

	SELECT SQ_ACEN_VOC_AGNT.NEXTVAL@DL_MCP FROM DUAL

INSERT INTO NMCP_ACEN_VOC_AGNT@DL_MCP(
   SEQ
  ,VOC_AGNT_CD
  ,VOC_AGNT_ID
  ,USE_YN
  ,REGST_ID
  ,REGST_DTTM
)VALUES (
	 #{seq}
	,#{vocAgntCd}
	,#{usrId}
	,#{useYn}
	,#{sessionUserId}
	,SYSDATE
)

mapper.update:
/*AcenVocAgntMapper.updateAcenVocAgnt*/
UPDATE NMCP_ACEN_VOC_AGNT@DL_MCP
SET USE_YN = #{useYn}
	 ,RVISN_ID = #{sessionUserId}
	 ,RVISN_DTTM = SYSDATE
WHERE SEQ = #{seq}
